SELECT setting_name
FROM chat_settings
WHERE setting_type = 'font';

SELECT COUNT(user_id) AS user_count
FROM user_settings
WHERE setting_id = 0 AND user_value = 'Arial Bold';

SELECT setting_name
FROM chat_settings
WHERE is_experimental = 1;

SELECT setting_name
FROM chat_settings
WHERE setting_id = 1;

SELECT COUNT(admin_id) AS active_admin_count
FROM client_admins
WHERE last_active > '2023-09-15';

SELECT user_value
FROM user_settings
WHERE user_id = 1 AND setting_id = 0;

SELECT setting_id, COUNT(DISTINCT user_id) AS user_count
FROM user_settings
GROUP BY setting_id;

SELECT COUNT(DISTINCT user_id) AS user_count
FROM user_settings
WHERE setting_id = 1;

SELECT COUNT(DISTINCT user_id) AS user_count
FROM user_settings
WHERE setting_id = (SELECT setting_id FROM chat_settings WHERE setting_name = 'fontSize');

SELECT user_value
FROM user_settings
WHERE user_id = 1;

SELECT COUNT(client_id) AS active_customizations_count
FROM client_customizations
WHERE is_active = 1 AND setting_id = 0;
